insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('tq_chatbot', 'tq chatbot', 'a multi-tenant funnel chatbot that talks to a visitor, scores how serious they are in real time, and pushes the hot ones straight to a booked call. build it once, reconfigure it per client.', array['runs for zero dollars with no api keys', 'promotes to production one key at a time']::text[], 'ai', 'featured', array['react', 'fastapi', 'supabase', 'groq', 'n8n', 'cloudflare']::text[], array['widget', 'fastapi', 'supabase', 'groq', 'n8n', 'booked call']::text[], 'https://github.com/adxoxo/chatbot-closer', '2026', 10, 13, 15, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('grimoire', 'grimoire', 'a local knowledge base that every coding agent reaches through a single mcp gateway. it ingests documents, remembers past sessions, and hands back only what is relevant, project by project. everything runs offline on my own machine.', array['retrieval, memory and compaction all verified', 'embeddings running on a local gpu']::text[], 'ai', 'featured', array['python', 'sqlite-vec', 'fastmcp', 'ollama', 'opentelemetry']::text[], array['agents', 'mcp gateway', 'sqlite-vec']::text[], 'https://github.com/adxoxo/grimoire', '2026', 20, 31, 44, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('goatedtracking', 'goatedtracking', 'a local-first monitoring system for a small goat farm here in the philippines. every goat wears a qr ear tag. scan it on the farm wifi and its whole profile opens: health records, vaccinations, pen, lineage. the internet is optional, not required.', array['one on-premise server, zero cloud for the core', 'works on any phone on the farm wifi']::text[], 'fullstack', 'featured', array['django', 'drf', 'postgres', 'react', 'docker']::text[], array['qr tag', 'phone browser', 'django api', 'postgres']::text[], 'https://github.com/adxoxo/GoatMonitoring', '2026', 30, 66, 13, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('grece', 'grece hydroponics', 'an automated nutrient film hydroponics setup. a raspberry pi and an arduino hold water flow, lighting, and nutrient dosing steady, while ph, ec, temperature and humidity stream to a django api you can watch and adjust from anywhere.', array['real-time monitoring and remote control', 'every reading logged for later tuning']::text[], 'embedded', 'featured', array['raspberry pi', 'arduino', 'python', 'django rest', 'c++']::text[], array['sensors', 'arduino', 'raspberry pi', 'django api']::text[], 'https://github.com/adxoxo/GRECE-Hydroponics-Monitoring-', '2026', 40, 66, 66, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('standup', 'standup dashboard', 'a single-screen github activity dashboard that answers one question: what is on my plate today. open prs, assigned issues, an activity streak and per-repo health, with day-over-day deltas.', array['every section fails independently', 'deltas are real history, not in-memory guesses']::text[], 'fullstack', 'archive', array['fastapi', 'react', 'recharts', 'sqlite']::text[], array['browser', 'fastapi', 'github api']::text[], 'https://github.com/adxoxo/GitDashboard', '2026', 50, 87, 31, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('moajump', 'moa jump', 'a k-pop themed vertical platformer built with phaser 3. three worlds, one target score, and it runs fully offline with no cdn and no backend.', array['plays on keyboard, touch and tilt', 'static files, hosts anywhere']::text[], 'fullstack', 'archive', array['phaser 3', 'javascript', 'gsap']::text[], array['phaser', 'static files', 'github pages']::text[], 'https://github.com/adxoxo/moa-jump', '2026', 60, 60, 42, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('moisture', 'moisture sensor', 'a diy device that measures the moisture content of rough rice grains over an esp32 and a serial link. built cheap and replaceable, on off-the-shelf parts, as the core of a thesis.', array['helps farmers judge grain readiness for storage', 'built to be replicated and adapted']::text[], 'embedded', 'archive', array['esp32', 'c++', 'serial']::text[], array['esp32', 'serial', 'readout']::text[], 'https://github.com/adxoxo/MoistureSensor', '2025', 70, 88, 66, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('smartpot', 'smart pot', 'a pot that reads light, temperature, humidity and soil moisture, then reports the plant''s health to a web and mobile view.', array['four sensors, one health status', 'readings served over a rest api']::text[], 'embedded', 'archive', array['esp32', 'sensors', 'django rest']::text[], array['sensors', 'esp32', 'django rest']::text[], 'https://github.com/adxoxo/SmartPot', '2023', 80, 76, 87, 'manual') on conflict (id) do nothing;
insert into projects (id, title, summary, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('carwash', 'invoice automation', 'an automation for a car detailing client that turns finished jobs into invoices and follow-ups that send themselves, so the owner stops chasing paperwork after hours.', array['invoices and reminders sent automatically', 'the owner gets the evening back']::text[], 'automation', 'archive', array['n8n', 'webhooks', 'email']::text[], array['job done', 'n8n', 'invoice + follow-up']::text[], null, '2026', 90, 13, 85, 'manual') on conflict (id) do nothing;
